#!/bin/sh
# updatebtw standalone installer
# Generated by make — do not edit directly

set -e

UPDATERBTW_ROOT="/usr/lib/updatebtw"
UPDATERBTW_CONFIG="/etc/updatebtw/updatebtw.conf"
export UPDATERBTW_ROOT UPDATERBTW_CONFIG

_check_root() {
  if [ "$(id -u)" -ne 0 ]; then
    echo "This installer must be run as root." >&2
    exit 1
  fi
}

_check_deps() {
  local missing=""
  ! command -v whiptail >/dev/null 2>&1 && missing="$missing libnewt"
  ! command -v git >/dev/null 2>&1 && missing="$missing git"
  ! command -v sudo >/dev/null 2>&1 && missing="$missing sudo"
  ! pacman -Qi base-devel >/dev/null 2>&1 && missing="$missing base-devel"

  if [ -z "$missing" ]; then
    return 0
  fi

  if command -v whiptail >/dev/null 2>&1; then
    whiptail --title "Missing Dependencies" --yesno \
      "The following packages are required:\n\n$missing\n\nInstall them now?" \
      12 50 || exit 1
  else
    echo "Missing dependencies:$missing"
    printf "Install now? [Y/n] "
    read -r answer
    case "$answer" in
      n|N|no|NO) exit 1 ;;
    esac
  fi

  # shellcheck disable=SC2086
  pacman -S --needed --noconfirm $missing
}

_install_aur_helper() {
  local helper="$1" user="$2"
  command -v "$helper" >/dev/null 2>&1 && return 0

  if [ "$(id -un)" != "$user" ]; then
    if ! id "$user" >/dev/null 2>&1; then
      useradd -m "$user" 2>/dev/null || true
    fi
    mkdir -p /etc/sudoers.d
    echo "$user ALL=(ALL) NOPASSWD: ALL" > "/etc/sudoers.d/$user" 2>/dev/null || true
  fi

  rm -rf "/tmp/$helper" 2>/dev/null || true
  if [ "$(id -un)" = "$user" ]; then
    git clone --depth=1 "https://aur.archlinux.org/$helper.git" "/tmp/$helper"
    cd "/tmp/$helper"
    makepkg -si --noconfirm
  else
    su - "$user" -c "
      git clone --depth=1 https://aur.archlinux.org/$helper.git /tmp/$helper
      cd /tmp/$helper
      makepkg -si --noconfirm
    "
  fi && printf "Installed %s\n" "$helper" || printf "Warning: failed to install %s\n" "$helper"

  command -v "$helper" >/dev/null 2>&1
}

_setup_aur_user() {
  local user="$1"
  [ -n "$user" ] || return 1

  if ! id "$user" >/dev/null 2>&1; then
    useradd -m "$user" 2>/dev/null || true
  fi

  rm -f "/etc/sudoers.d/$user" 2>/dev/null || true
  mkdir -p /etc/sudoers.d
  echo "$user ALL=(ALL) NOPASSWD: /usr/bin/pacman" > "/etc/sudoers.d/updatebtw-$user"
}

main() {
  _check_root
  _check_deps

  whiptail() { command whiptail "$@" </dev/tty; }

  whiptail --title "updatebtw" --msgbox \
    "Welcome to updatebtw — the automatic Arch Linux update utility.\n\nNOTE: This project is NOT affiliated with or endorsed by Arch Linux.\nIt is an unofficial third-party tool.\n\nThis installer will configure automatic system updates on your system." \
    12 60

  local freq_choice

  AUR_HELPER=$(whiptail --title "AUR Helper" --radiolist \
    "Select your preferred AUR helper:" 12 65 2 \
    "yay"  "Original Go-based AUR helper (recommended)" ON \
    "paru" "Modern Rust-based AUR helper"             OFF \
     3>&1 1>&2 2>&3) || exit 1

  local detected_user="aur_builder"
  AUR_USER=$(whiptail --title "AUR User" --inputbox \
    "Run AUR helpers (yay/paru) as which user?\n\nThis user will be created if it doesn't already exist.\nWe do NOT recommend using your personal user account." 10 60 "$detected_user" \
    3>&1 1>&2 2>&3) || exit 1

  local detected_flatpak_user="${SUDO_USER:-$(id -un)}"
  FLATPAK_USER=$(whiptail --title "Flatpak User" --inputbox \
    "Run flatpak updates as which user?\n\nThis should be your personal user account,\nsince flatpak installs per-user packages." 10 60 "$detected_flatpak_user" \
    3>&1 1>&2 2>&3) || exit 1

  freq_choice=$(whiptail --title "Update Frequency" --radiolist \
    "How often should updates run?" 14 50 3 \
    "daily"   "Update every day" ON \
    "weekly"  "Update once a week" OFF \
    "monthly" "Update once a month" OFF \
    3>&1 1>&2 2>&3) || exit 1
  UPDATE_FREQUENCY="$freq_choice"

  UPDATE_TIME=$(whiptail --title "Update Time" --inputbox \
    "What time should updates run? (HH:MM, 24-hour format)" 8 60 "06:00" \
    3>&1 1>&2 2>&3) || exit 1

  if whiptail --title "Boot Update" --yesno \
    "Run an update every time the system boots?\n\nThis is useful for systems that are not always on." 10 60; then
    RUN_AT_BOOT="true"
  else
    RUN_AT_BOOT="false"
  fi

  if whiptail --title "Mirrorlist" --yesno \
    "Automatically update mirrorlist via reflector?\n\nThis keeps your package sources fast and up to date." 10 60; then
    ENABLE_REFLECTOR="true"
    REFLECTOR_COUNTRY=$(whiptail --title "Mirror Country" --inputbox \
      "Mirror country (e.g. 'United States', 'Germany'):" 8 60 "United States" \
      3>&1 1>&2 2>&3) || exit 1
    REFLECTOR_INTERVAL=$(whiptail --title "Mirror Update Interval" --inputbox \
      "How often (in days) should the mirrorlist be refreshed?" 8 60 "30" \
      3>&1 1>&2 2>&3) || exit 1
  else
    ENABLE_REFLECTOR="false"
  fi

  if whiptail --title "Silent Boot" --yesno \
    "Configure silent boot?\n\nReduces kernel messages during boot for a cleaner experience.\nModifies boot loader entries, mkinitcpio, and systemd-fsck services." 12 60; then
    SILENT_BOOT="true"
  else
    SILENT_BOOT="false"
  fi

  local summary
  summary="AUR Helper: $AUR_HELPER\n"
  summary="${summary}Frequency: $UPDATE_FREQUENCY at $UPDATE_TIME\n"
  summary="${summary}Run at boot: $RUN_AT_BOOT\n"
  summary="${summary}Reflector: $ENABLE_REFLECTOR"
  if [ "$ENABLE_REFLECTOR" = "true" ]; then
    summary="${summary} (country: $REFLECTOR_COUNTRY, interval: ${REFLECTOR_INTERVAL:-30}d)\n"
  else
    summary="${summary}\n"
  fi
  summary="${summary}AUR user: $AUR_USER\n"
  summary="${summary}Flatpak user: $FLATPAK_USER\n"
  summary="${summary}Silent boot: $SILENT_BOOT\n"

  if ! whiptail --title "Confirm" --yesno "Apply the following configuration?\n\n${summary}" 16 65; then
    exit 0
  fi

  echo "Installing AUR helper..."
  _install_aur_helper "$AUR_HELPER" "$AUR_USER" || true
  echo "Configuring AUR user..."
  _setup_aur_user "$AUR_USER" >/dev/null 2>&1 || true
  echo "Writing configuration..."
  write_config
  if [ "$ENABLE_REFLECTOR" = "true" ] && ! command -v reflector >/dev/null 2>&1; then
    echo "Installing reflector..."
    pacman -S --needed --noconfirm reflector >/dev/null 2>&1 || true
  fi
  echo "Installing system files..."
  install_system_files
  echo "Installing systemd units..."
  install_systemd_units
  echo "Enabling timer..."
  enable_timer
  echo "Done."

  if [ "$SILENT_BOOT" = "true" ]; then
    silent_boot
  fi

  whiptail --title "Complete" --msgbox \
    "updatebtw has been installed and configured.\n\nUpdates will run automatically on your schedule." \
    8 50
}

# === config module ===
# updatebtw config module

UPDATERBTW_CONFIG="${UPDATERBTW_CONFIG:-/etc/updatebtw/updatebtw.conf}"
AUR_USER="${AUR_USER:-aur_builder}"
FLATPAK_USER="${FLATPAK_USER:-${AUR_USER:-aur_builder}}"

read_config() {
  [ -f "$UPDATERBTW_CONFIG" ] && . "$UPDATERBTW_CONFIG" || true
}

write_config() {
  local config_dir
  config_dir="$(dirname "$UPDATERBTW_CONFIG")"
  mkdir -p "$config_dir"
  cat > "$UPDATERBTW_CONFIG" << EOF
# updatebtw configuration
# Generated by updatebtw installer

AUR_HELPER="${AUR_HELPER:-yay}"
UPDATE_FREQUENCY="${UPDATE_FREQUENCY:-weekly}"
UPDATE_TIME="${UPDATE_TIME:-06:00}"
RUN_AT_BOOT="${RUN_AT_BOOT:-false}"
ENABLE_REFLECTOR="${ENABLE_REFLECTOR:-true}"
REFLECTOR_COUNTRY="${REFLECTOR_COUNTRY:-United States}"
REFLECTOR_PROTOCOL="${REFLECTOR_PROTOCOL:-https}"
REFLECTOR_INTERVAL="${REFLECTOR_INTERVAL:-30}"
SILENT_BOOT="${SILENT_BOOT:-false}"
AUR_USER="${AUR_USER:-aur_builder}"
FLATPAK_USER="${FLATPAK_USER:-${SUDO_USER:-$(id -un)}}"
EOF
}

validate_config() {
  local errors=""
  case "${AUR_HELPER:-yay}" in
    yay|paru) ;;
    *) errors="${errors}error: AUR_HELPER must be 'yay' or 'paru' (got: ${AUR_HELPER})\n" ;;
  esac
  case "${UPDATE_FREQUENCY:-weekly}" in
    daily|weekly|monthly) ;;
    *) errors="${errors}error: UPDATE_FREQUENCY must be 'daily', 'weekly', or 'monthly' (got: ${UPDATE_FREQUENCY})\n" ;;
  esac
  if [ -n "$errors" ]; then
    printf '%b' "$errors" >&2
    return 1
  fi
  return 0
}

calendar_from_config() {
  local time="${UPDATE_TIME:-06:00}"
  case "${UPDATE_FREQUENCY:-weekly}" in
    daily)   echo "*-*-* ${time}:00" ;;
    weekly)  echo "Mon *-*-* ${time}:00" ;;
    monthly) echo "*-*-01 ${time}:00" ;;
  esac
}

# === backup module ===
# updatebtw backup module

UPDATERBTW_BACKUP_DIR="${UPDATERBTW_BACKUP_DIR:-/var/lib/updatebtw/backups}"
UPDATERBTW_BACKUP_KEEP="${UPDATERBTW_BACKUP_KEEP:-10}"

backup_file() {
  local src="$1"
  [ -f "$src" ] || return 1
  mkdir -p "$UPDATERBTW_BACKUP_DIR"
  local name
  name="$(basename "$src")"
  local ts
  ts="$(date "+%Y%m%d_%H%M%S")"
  cp -a "$src" "$UPDATERBTW_BACKUP_DIR/${name}.${ts}"
  _rotate_backups "$name"
}

restore_file() {
  local src="$1"
  local name
  name="$(basename "$src")"
  local latest
  latest="$(ls -t "$UPDATERBTW_BACKUP_DIR/${name}."* 2>/dev/null | head -1)"
  [ -n "$latest" ] || return 1
  cp -a "$latest" "$src"
}

list_backups() {
  local name="${1:-}"
  if [ -n "$name" ]; then
    ls -1t "$UPDATERBTW_BACKUP_DIR/${name}."* 2>/dev/null || true
  else
    ls -1t "$UPDATERBTW_BACKUP_DIR"/* 2>/dev/null || true
  fi
}

_rotate_backups() {
  local name="$1"
  local keep="${UPDATERBTW_BACKUP_KEEP:-10}"
  ls -t "$UPDATERBTW_BACKUP_DIR/${name}."* 2>/dev/null \
    | tail -n +$((keep + 1)) \
    | xargs rm -f 2>/dev/null || true
}

# === silent-boot module ===
# updatebtw silent boot module

set_kernel_options() {
  local entries_dir="${1:-/boot/loader/entries}"
  local kernel_options="${2:-quiet loglevel=3 vt.global_cursor_default=0 systemd.show_status=auto rd.udev.log_level=3 nowatchdog modprobe.blacklist=sp5100_tco audit=0}"

  read -ra option_tokens <<< "$kernel_options"
  local option_keys=()
  local token
  for token in "${option_tokens[@]}"; do
    option_keys+=("${token%%=*}")
  done

  [ -d "$entries_dir" ] || return 0
  local entry
  for entry in "$entries_dir"/*; do
    [ -f "$entry" ] || continue
    backup_file "$entry" 2>/dev/null || true

    local tmpfile
    tmpfile="$(mktemp)"
    local line

    while IFS= read -r line; do
      read -ra line_tokens <<< "$line"
      if [ "${line_tokens[0]}" = "options" ]; then
        local out_line=""
        local token2 key2 skip
        for token2 in "${line_tokens[@]}"; do
          key2="${token2%%=*}"
          skip=false
          local k
          for k in "${option_keys[@]}"; do
            if [ "$key2" = "$k" ]; then
              skip=true
              break
            fi
          done
          if ! $skip; then
            out_line="$out_line$token2 "
          fi
        done
        out_line="$out_line$kernel_options"
        printf '%s\n' "$out_line" > "$tmpfile"
      else
        printf '%s\n' "$line" >> "$tmpfile"
      fi
    done < "$entry"

    chmod 755 "$tmpfile"
    chown root:root "$tmpfile"
    mv "$tmpfile" "$entry"
  done
}

set_printk() {
  local dest="${1:-/etc/sysctl.d/20-quiet-printk.conf}"
  local dest_dir
  dest_dir="$(dirname "$dest")"
  mkdir -p "$dest_dir"
  backup_file "$dest" 2>/dev/null || true
  printf 'kernel.printk = 3 3 3 3\n' > "$dest"
}

patch_mkinitcpio() {
  local src="${1:-/etc/mkinitcpio.conf}"
  [ -f "$src" ] || return 0
  backup_file "$src" 2>/dev/null || true

  local tmpfile
  tmpfile="$(mktemp)"
  local line

  while IFS= read -r line; do
    local key="${line%%=*}"
    key="${key## }"
    if [ "$key" = "HOOKS" ]; then
      local new_line
      new_line="$(printf '%s\n' "$line" | sed 's/udev/systemd fsck/g')"
      new_line="$(printf '%s\n' "$new_line" | sed 's/\(.*\)fsck\(.*\)fsck\(.*\)/\1fsck\2\3/g')"
      new_line="$(printf '%s\n' "$new_line" | sed 's/  / /g')"
      printf '%s\n' "$new_line" >> "$tmpfile"
    else
      printf '%s\n' "$line" >> "$tmpfile"
    fi
  done < "$src"

  chmod 644 "$tmpfile"
  chown root:root "$tmpfile"
  mv "$tmpfile" "$src"
}

patch_fsck_services() {
  local files=("$@")
  if [ ${#files[@]} -eq 0 ]; then
    files=(/usr/lib/systemd/system/systemd-fsck@.service /usr/lib/systemd/system/systemd-fsck-root.service)
  fi

  local file
  for file in "${files[@]}"; do
    [ -f "$file" ] || continue
    backup_file "$file" 2>/dev/null || true

    local tmpfile
    tmpfile="$(mktemp)"
    local in_service=false
    local line key

    while IFS= read -r line; do
      key="${line%%=*}"
      if [ "$line" = "[Service]" ]; then
        in_service=true
        printf '%s\n' "$line" >> "$tmpfile"
        printf 'StandardOutput=null\n' >> "$tmpfile"
        printf 'StandardError=journal+console\n' >> "$tmpfile"
      elif $in_service && { [ "$key" = "StandardOutput" ] || [ "$key" = "StandardError" ]; }; then
        :
      else
        printf '%s\n' "$line" >> "$tmpfile"
      fi
    done < "$file"

    chmod 644 "$tmpfile"
    chown root:root "$tmpfile"
    mv "$tmpfile" "$file"
  done
}

silent_boot() {
  set_kernel_options
  set_printk
  patch_mkinitcpio
  patch_fsck_services

  if [ -f /etc/mkinitcpio.conf ] && [ -f /boot/vmlinuz-linux ]; then
    mkinitcpio -P
  fi

  touch ~root/.hushlogin

  systemctl unmask systemd-journald-audit.socket 2>/dev/null || true
  systemctl stop systemd-journald-audit.socket 2>/dev/null || true
  systemctl disable systemd-journald-audit.socket 2>/dev/null || true
  systemctl mask systemd-journald-audit.socket 2>/dev/null || true
}

# === updater module ===
# updatebtw updater module

update_packages() {
  trap '_notify critical "updatebtw" "Shutdown blocked — system update in progress, please wait"' SIGTERM
  read_config

  if [ -e /var/lib/pacman/db.lck ]; then
    _notify error "Update Failed" "/var/lib/pacman/db.lck exists"
    return 1
  fi

  if [ "${ENABLE_REFLECTOR:-true}" = "true" ]; then
    _update_mirrorlist || true
  fi

  _notify info "updatebtw" "Starting system update"
  local helper="${AUR_HELPER:-yay}"
  local aur_user="${AUR_USER:-aur_builder}"
  case "$helper" in
    yay)  _run_as_user "$aur_user" yay -Syyuu --noconfirm ;;
    paru) _run_as_user "$aur_user" paru -Syyuu --noconfirm ;;
  esac

  local exit_code=$?
  if [ $exit_code -ne 0 ]; then
    _notify error "Update Failed" "AUR helper exited with code $exit_code"
    return $exit_code
  fi

  if command -v flatpak >/dev/null 2>&1; then
    local flatpak_user="${FLATPAK_USER:-$aur_user}"
    _run_as_user "$flatpak_user" flatpak update --noninteractive || {
      _notify error "Flatpak Update Failed" "flatpak exited with code $?"
      return 1
    }
  fi

  _notify success "updatebtw" "Update complete"
}

_update_mirrorlist() {
  local mirrorlist="/etc/pacman.d/mirrorlist"
  local interval=$(( ${REFLECTOR_INTERVAL:-30} * 86400 ))

  if [ -f "$mirrorlist" ]; then
    local last_update
    last_update="$(date -r "$mirrorlist" "+%s")"
    local now
    now="$(date "+%s")"
    local delta=$(( now - last_update ))
    if [ $delta -lt $interval ]; then
      return 0
    fi
  fi

  backup_file "$mirrorlist"
  _notify info "updatebtw" "Updating mirrorlist via reflector"
  if ! reflector --save "$mirrorlist" \
       --country "${REFLECTOR_COUNTRY:-United States}" \
       --protocol "${REFLECTOR_PROTOCOL:-https}" \
       --latest 5; then
    _notify error "Reflector Failed" "Mirrorlist update failed"
    return 1
  fi
}

_notify() {
  local type="$1"
  local summary="$2"
  local body="$3"
  echo "[$type] $summary: $body"
  if command -v notify-send >/dev/null 2>&1; then
    local urgency="normal"
    local icon="update-none"
    case "$type" in
      error)   urgency="critical"; icon="error" ;;
      success) urgency="normal";   icon="update-none" ;;
      info)    urgency="low";      icon="update-none" ;;
    esac
    notify-send -i "$icon" -u "$urgency" -a "updatebtw" "$summary" "$body"
  fi
}

_run_as_user() {
  local user="$1"
  shift
  if [ "$(id -un)" = "$user" ]; then
    "$@"
  elif command -v runuser >/dev/null 2>&1; then
    runuser -u "$user" -- "$@"
  else
    su - "$user" -c "$*"
  fi
}

