}

enable_timer() {
  systemctl daemon-reload 2>/dev/null || true
  systemctl enable --now updatebtw-update.timer 2>/dev/null || true
  if [ "$RUN_AT_BOOT" = "true" ]; then
    systemctl enable updatebtw-boot.service 2>/dev/null || true
  fi
}

